INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$No-download browser streaming$q$, $q$Hosts and attendees join live sessions through a browser link using WebRTC, with no app or plug-in installation required.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Automatic evergreen replays$q$, $q$Every live session is recorded automatically and can be repackaged as an on-demand replay to keep generating registrations and sales.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Built-in ticketing and subscriptions$q$, $q$Hosts can charge for individual events or recurring access directly through Crowdcast's integrated payments, without a separate checkout tool.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Live polls and Q&A$q$, $q$Real-time polling and a moderated question queue let hosts gather feedback and manage audience questions during a broadcast.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Audience spotlighting$q$, $q$Hosts can bring audience members on camera to ask questions or participate directly in the live show.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Multistreaming$q$, $q$Pro and Business plans can simultaneously stream to external destinations such as YouTube and Facebook Live.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Custom registration fields$q$, $q$Hosts can collect custom attendee information at signup for segmentation and follow-up marketing.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Team seats$q$, $q$Multiple team members can be added to co-host, moderate, or manage events depending on plan tier.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$No download required for attendees, reducing friction and no-shows$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Monetization (tickets, subscriptions) is built directly into the platform$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Automatic replay library extends the value of every live event$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Simple host dashboard compared to production-heavy streaming tools$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Percentage-based transaction fees on paid events can add up at scale$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Session length and streaming hours are capped by plan tier$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Smaller third-party integration ecosystem than larger, better-funded competitors$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Higher attendee caps and multistreaming require upgrading to pricier plans$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Do attendees need to download an app to join a Crowdcast event?$q$, $q$No. Crowdcast runs entirely in the browser using WebRTC, so hosts and attendees join through a link without installing any software.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Can I charge for access to a Crowdcast event?$q$, $q$Yes. Crowdcast has built-in ticketing and subscription billing so hosts can charge for individual events or ongoing access, with Crowdcast taking a percentage-based transaction fee that varies by plan.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Does Crowdcast offer a free plan?$q$, $q$Crowdcast does not have a permanent free plan, but it offers a 14-day free trial limited to 60-minute sessions and up to ten live attendees.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$What happens to a Crowdcast session after it ends?$q$, $q$Sessions are automatically recorded and become on-demand replays that hosts can keep available to registrants or sell as evergreen content.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$How is Crowdcast priced?$q$, $q$Crowdcast uses three monthly plans, Lite at $49, Pro at $89, and Business at $195, which scale attendee limits, streaming hours, storage, and team seats, with roughly 30% savings on annual billing.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$What is Crowdcast best suited for?$q$, $q$Crowdcast is best suited for online course creators, coaches, authors, and membership communities that want to combine live broadcasting, audience interaction, and monetization in a single tool.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Paid online summits$q$, $q$Event organizers sell tickets to multi-day virtual summits with multiple speakers and monetize the replay library afterward.$q$, $q$Event organizers and conference producers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Membership-gated live shows$q$, $q$Coaches and creators run recurring live Q&A or teaching sessions available exclusively to paying subscribers.$q$, $q$Coaches, creators, and membership businesses$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Lead-generation webinars$q$, $q$B2B marketers host free registration webinars to capture leads and nurture them with automatic replay access.$q$, $q$B2B marketing teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Free Trial$q$, $q$Free$q$, $q$14 days$q$, NULL, $q$["60-minute sessions","Up to 10 live attendees"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Lite$q$, $q$$49/month$q$, $q$monthly$q$, NULL, $q$["100+ live attendees","10 streaming hours/month","1 team seat","1 GB Studio storage","2-hour session limit","5% transaction fee"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Pro$q$, $q$$89/month$q$, $q$monthly$q$, NULL, $q$["250+ live attendees","20 streaming hours/month","2 team seats","5 GB Studio storage","4-hour session limit","1 multistream destination","Custom registration fields"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$Business$q$, $q$$195/month$q$, $q$monthly$q$, NULL, $q$["1,000+ live attendees","40 streaming hours/month","4 team seats","10 GB Studio storage","6-hour session limit","3 multistream destinations","2% transaction fee"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Crowdcast is a live video platform designed for hosting webinars, online courses, and virtual summits directly in the browser, with no software download required for hosts or attendees. Founded in 2015 by Sai Hossain, the company has grown as a lean, founder-led business rather than a venture-fueled hypergrowth startup.$q$, $q$The platform combines live broadcasting, audience interaction, and monetization tools in one product, making it popular with course creators, coaches, and membership businesses who want to avoid stitching together separate video, registration, and payment tools.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Every Crowdcast session runs on WebRTC streaming in the browser and is automatically recorded, turning live events into an evergreen library of on-demand replays that hosts can continue to sell or use for lead generation.$q$, $q$Built-in interactivity tools include live polls, moderated Q&A queues, audience spotlighting, and persistent chat, while integrated ticketing and subscription billing let hosts charge for access without a separate checkout tool.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Crowdcast offers a 14-day free trial, then three monthly plans: Lite at $49/month, Pro at $89/month, and Business at $195/month, each raising attendee caps, streaming hours, team seats, and storage while lowering the percentage-based transaction fee on paid tickets.$q$, $q$Annual billing saves roughly 30% compared to monthly pricing, and teams can add extra seats or streaming hours a la carte if they outgrow their plan's included allotment.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('a877cfed-31d8-488b-bd3f-59adb9df9eea', '610c2598-d057-4727-bf3b-e907b0daed7f') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$Crowdsourced blocklists$q$, $q$Attack signals detected anywhere in the CrowdSec community are anonymized and shared, updating every participant's blocklist in real time.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$Open-source Security Engine$q$, $q$The core detection engine is MIT-licensed and free to self-host on Linux servers, containers, or edge devices.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$Modular bouncers$q$, $q$Remediation components integrate with iptables/nftables, Nginx, Apache, Traefik, HAProxy, WordPress, and cloud security groups to enforce blocks automatically.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$CrowdSec Console$q$, $q$A centralized hosted dashboard for monitoring alerts and managing remediation policy across many enrolled Security Engines.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$Cyber Threat Intelligence API$q$, $q$A paid API returning IP reputation, MITRE ATT&CK classification, and contextual attack data across more than 30 criteria.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$Platinum Blocklists$q$, $q$Curated, industry- and country-specific IP blocklists, including an AI-crawler blocklist, for teams that want CrowdSec's data without deploying the engine.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$AppSec/WAF component$q$, $q$Application-layer protection rules that extend CrowdSec's detection into web request filtering.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$Multi-channel alerting$q$, $q$Surge and anomaly notifications can be routed to email, Slack, and other channels for faster incident response.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$Core Security Engine is free, open source, and self-hostable$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$Blocklists improve automatically as more community members detect new attacks$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$Modular bouncers integrate with common firewalls, web servers, and WordPress$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$Transparent, pay-as-you-grow pricing for premium and enterprise tiers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$Full value depends on network effects, so blocklist quality varies by threat category$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$Enterprise-grade blocklists and local CTI replication carry four-figure monthly costs$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$Requires log access and some server-side configuration to deploy effectively$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$Smaller company than large incumbent threat-intel vendors, with a narrower support footprint$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$Is CrowdSec free to use?$q$, $q$Yes. The core CrowdSec Security Engine and the Community Console tier are free and open source under the MIT license. Paid tiers add premium blocklists, a CTI API, and enterprise support.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$How does CrowdSec's crowdsourced detection work?$q$, $q$When a CrowdSec deployment detects an attack, an anonymized signal is shared with the CrowdSec network, and every other participant's blocklist is updated with that malicious IP, creating a collective defense.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$What is a CrowdSec bouncer?$q$, $q$A bouncer is a remediation component that enforces blocking decisions made by the Security Engine, integrating with tools like firewalls, Nginx, Apache, and WordPress.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$Can CrowdSec replace a traditional firewall?$q$, $q$No. CrowdSec is designed to complement existing firewalls and WAFs by adding crowdsourced detection and blocking, not to replace network perimeter security entirely.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$Who uses CrowdSec?$q$, $q$CrowdSec is used by individual server administrators, DevOps teams, managed service providers, and larger organizations including governments and financial institutions, with reported installs exceeding 100,000 across roughly 175 countries.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$What is the difference between CrowdSec and Fail2ban?$q$, $q$Fail2ban blocks attackers based only on what a single server observes, while CrowdSec shares detection signals across its whole user community so every participant benefits from attacks detected elsewhere.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$Self-managed server protection$q$, $q$DevOps teams deploy the free Security Engine on their servers to automatically block brute-force logins, scanners, and bots using community threat data.$q$, $q$DevOps and infrastructure teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$Managed hosting and MSP security$q$, $q$Service providers roll out CrowdSec across client infrastructure and use the Console to centrally monitor and manage remediation at scale.$q$, $q$Managed service providers$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$IP reputation enrichment$q$, $q$Security teams integrate the CTI API into their own SIEM or fraud tooling to enrich alerts with real-time IP reputation and MITRE technique data.$q$, $q$Security and fraud engineering teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$Community$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Open-source Security Engine","Access to community blocklists","Behavioral detection scenarios"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$Console Premium$q$, $q$Pay-as-you-grow (per enrolled Security Engine)$q$, $q$monthly$q$, NULL, $q$["Premium Community Blocklist","Surge alert notifications","Extended alert retention","Centralized list management"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$CTI / IP Reputation$q$, $q$From $49/month (5,000 queries)$q$, $q$monthly$q$, NULL, $q$["30+ contextual IP criteria","MITRE technique classification","Hourly updated data"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$Platinum Blocklists$q$, $q$From $1,900/month (SMB)$q$, $q$monthly$q$, NULL, $q$["Industry and country-specific blocklists","AI-crawler blocklist","Unlimited endpoints within the company"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$CrowdSec is an open-source intrusion detection and prevention platform that turns attack data from its global user base into a shared, real-time blocklist of malicious IP addresses. Founded in 2020 in France by Philippe Humeau, Laurent Soubrevilla, and Thibault Koechlin, the company built its Security Engine as a free, MIT-licensed alternative to running detection in isolation.$q$, $q$When one deployment detects an attack such as a brute-force attempt or a scraping bot, the anonymized signal is shared across the network so every participant benefits from what any other participant has already seen, creating a crowdsourced neighborhood watch for internet infrastructure.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The free, self-hosted Security Engine parses logs using configurable detection scenarios and hands off enforcement to modular bouncers that integrate with firewalls, Nginx, Apache, WordPress, and cloud security groups.$q$, $q$The hosted Console gives teams centralized visibility across many enrolled engines, while the paid CTI API and Platinum Blocklists expose CrowdSec's aggregated threat data for teams that want IP reputation scoring without deploying the full engine.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$CrowdSec's Security Engine and Community Console tier are free to use. Paid options layer on top: Console Premium is billed per enrolled Security Engine on a pay-as-you-grow basis, the CTI/IP Reputation API starts near $49/month for 5,000 queries, and Platinum Blocklists start around $1,900/month for SMB customers.$q$, $q$Enterprise customers needing on-premises threat data replication for latency or compliance reasons can access local CTI synchronization starting near $9,000/month.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('521d7edd-be93-4cc5-b678-97bf55389e62', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$Single lightweight agent$q$, $q$One agent covers antivirus, EDR, and telemetry collection rather than requiring separate tools per capability.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$Cloud-native threat correlation$q$, $q$Telemetry is analyzed in CrowdStrike's cloud backend using AI models trained in part on real-world incident-response data.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$Endpoint detection and response (EDR)$q$, $q$Deep visibility into endpoint activity enables investigation, threat hunting, and rapid containment of active attacks.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$Identity threat protection$q$, $q$Monitors identity infrastructure such as Active Directory and Entra ID for credential misuse and lateral movement.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$Cloud workload protection (CNAPP)$q$, $q$Extends Falcon's detection to cloud workloads, containers, and Kubernetes environments.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$Charlotte AI$q$, $q$An AI security analyst that summarizes incidents in natural language and can recommend or automate response actions.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$Falcon Complete managed service$q$, $q$A fully managed offering where a dedicated CrowdStrike team monitors, investigates, and remediates threats around the clock.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$Next-gen SIEM and log management$q$, $q$Centralized log collection and search built on CrowdStrike's Falcon LogScale technology.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$Single agent reduces endpoint performance overhead versus multi-tool stacks$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$Cloud-native architecture enables real-time detection without waiting for signature updates$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$Backed by CrowdStrike's own threat-hunting and incident-response intelligence$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$Modular platform lets customers add identity, cloud, and SIEM capabilities as they mature$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$Full-platform deployments can be significantly more expensive than entry-level tiers suggest$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$Falcon Go is capped at 100 devices, requiring an upgrade as organizations grow$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$Advanced modules and Falcon Complete require custom quotes rather than transparent pricing$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$The July 2024 global outage caused by a faulty sensor update remains a notable incident in the product's history$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$What is CrowdStrike Falcon?$q$, $q$CrowdStrike Falcon is a cloud-native cybersecurity platform that uses a single lightweight agent to deliver antivirus, endpoint detection and response, identity protection, cloud security, and more.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$How much does CrowdStrike Falcon cost?$q$, $q$Falcon Go starts at $7.99 per device per month ($59.99 billed annually), Falcon Pro is $14.99/month ($99.99 annually), and Falcon Enterprise is $19.99/month ($184.99 annually); Falcon Complete and advanced modules are custom-quoted.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$What is Falcon Complete?$q$, $q$Falcon Complete is CrowdStrike's fully managed detection and response service, where a dedicated CrowdStrike team monitors, investigates, and remediates threats on the customer's behalf around the clock.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$How many devices can Falcon Go support?$q$, $q$Falcon Go is limited to a maximum of 100 devices, making it suitable primarily for small businesses; larger organizations need Falcon Pro or Enterprise.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$What is Charlotte AI?$q$, $q$Charlotte AI is CrowdStrike's generative AI security analyst that summarizes alerts and can recommend or automate incident response actions within the Falcon platform.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$Who are CrowdStrike Falcon's main competitors?$q$, $q$Falcon's closest competitors include Microsoft Defender for Endpoint, SentinelOne, Palo Alto Networks Cortex XDR, Sophos Intercept X, and Trend Micro.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$Enterprise endpoint protection$q$, $q$Security operations teams deploy Falcon across thousands of endpoints for real-time threat detection, investigation, and response.$q$, $q$Enterprise SOC and IT security teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$Fully managed threat response$q$, $q$Resource-constrained organizations use Falcon Complete to outsource 24/7 monitoring and remediation to CrowdStrike's own analysts.$q$, $q$Mid-market companies without a large in-house SOC$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$Cloud and identity security$q$, $q$Organizations extend Falcon into cloud workloads and identity infrastructure to detect lateral movement and cloud misconfigurations.$q$, $q$Cloud security and identity teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$Falcon Go$q$, $q$$7.99/device/month ($59.99/device/year)$q$, $q$monthly or annual$q$, NULL, $q$["Next-gen antivirus","Device control","Mobile device protection","Up to 100 devices"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$Falcon Pro$q$, $q$$14.99/device/month ($99.99/device/year)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Go","Firewall management","Endpoint detection and response"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$Falcon Enterprise$q$, $q$$19.99/device/month ($184.99/device/year)$q$, $q$monthly or annual$q$, NULL, $q$["Everything in Pro","Threat intelligence and hunting"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$Falcon Complete$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["24/7 managed detection and response","Dedicated CrowdStrike analyst team","Breach prevention warranty"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$CrowdStrike Falcon is a cloud-native cybersecurity platform built around a single lightweight agent that streams endpoint telemetry to CrowdStrike's cloud backend for real-time detection and response. Founded in 2011 by George Kurtz, Dmitri Alperovitch, and Gregg Marston, CrowdStrike launched Falcon's first product in 2013 and is now headquartered in Austin, Texas, as a publicly traded company with more than 10,000 employees.$q$, $q$Falcon has grown from an antivirus replacement into a broad security platform spanning endpoint protection, extended detection and response, identity threat protection, cloud workload security, and next-generation SIEM, delivered through more than 30 modules layered on top of the same base agent.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The single-agent architecture avoids the performance overhead of running separate tools for antivirus, EDR, and log collection, while CrowdStrike's cloud backend correlates telemetry across all customers using AI models informed by its own threat-hunting and incident-response investigations.$q$, $q$The Charlotte AI security analyst can summarize alerts and recommend or automate response steps, and CrowdStrike's managed Falcon Complete service adds a dedicated human team that monitors and remediates threats around the clock.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$CrowdStrike sells Falcon in tiered bundles: Falcon Go starts at $7.99/device/month ($59.99 annually) for small businesses up to 100 devices, Falcon Pro is $14.99/month ($99.99 annually) adding firewall management and EDR, and Falcon Enterprise is $19.99/month ($184.99 annually) adding threat hunting and intelligence.$q$, $q$Falcon Complete, the fully managed detection and response tier, along with advanced modules like cloud security and identity protection, is custom-quoted, and typical enterprise deployments across the full platform commonly total tens of thousands of dollars per year or more.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', '381992fc-7997-449c-9c68-511f0dce4b99') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', 'f24fb236-dfcf-452c-9b9e-02926f4383d9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('44c37134-11ad-4612-bb00-c445b91881e5', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$Zero-knowledge encryption$q$, $q$All content is encrypted and decrypted client-side, so the server never has access to readable document data.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$Real-time collaborative editing$q$, $q$The ChainPad CRDT algorithm enables multiple users to co-edit encrypted documents simultaneously without conflicts.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$Full office suite$q$, $q$Includes rich text documents, spreadsheets, presentations, a code/markdown editor, kanban boards, a whiteboard, and forms.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$Self-hostable$q$, $q$The complete server software is open source and can be deployed on-premise or on private infrastructure at no licensing cost.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$Encrypted file drive$q$, $q$Users get an encrypted personal drive for storing and organizing documents and files.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$Forms and surveys$q$, $q$Encrypted form creation lets users collect responses without exposing submitted data to the server.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$SSO integration (Enterprise)$q$, $q$Enterprise plans support single sign-on integration for centralized identity management.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$No vendor lock-in$q$, $q$As open-source software, organizations can export their data and migrate between the public instance and self-hosted deployments freely.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$True end-to-end, zero-knowledge encryption not offered by most mainstream office suites$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$Free and open source, with no-cost self-hosting available$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$Covers most common office suite needs (docs, sheets, slides, kanban, forms) in one product$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$Backed by an established open-source company (XWiki SAS) rather than an anonymous project$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$Self-hosting requires technical setup and ongoing server maintenance$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$Feature depth and polish can lag behind mainstream suites like Google Workspace or Microsoft 365$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$Enterprise pricing tiers can be costly for larger organizations compared to open self-hosting$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$Small maintaining team relative to the scope of a full office suite$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$Is CryptPad free to use?$q$, $q$Yes. CryptPad is free and open source, and free accounts with baseline storage are available on the flagship CryptPad.fr instance; it can also be self-hosted at no cost.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$What does 'end-to-end encrypted' mean for CryptPad documents?$q$, $q$All encryption and decryption happens in the user's browser before data is sent to the server, so the server operator cannot read document content, file names, or passwords.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$Who develops and maintains CryptPad?$q$, $q$CryptPad is maintained by a dedicated team within XWiki SAS, a Paris-based open-source software company, led by David Benque, building on original work by Caleb James De Lisle.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$Can I self-host CryptPad?$q$, $q$Yes. CryptPad's server software is open source and can be self-hosted on your own infrastructure at no licensing cost, giving full control over data location and privacy.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$What is included in CryptPad's office suite?$q$, $q$CryptPad includes rich text documents, spreadsheets, presentations, a code/markdown editor, kanban boards, a whiteboard, forms, and encrypted file storage.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$How much do CryptPad Enterprise plans cost?$q$, $q$Enterprise plans start around €1,500 per year and scale by user count and storage, from about €3,000/year for 50 users and 100GB up to about €25,000/year for 1,000 users and 1TB, with education and nonprofit discounts available.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$Privacy-sensitive collaboration$q$, $q$Journalists, NGOs, and activists use CryptPad to draft and co-edit documents without exposing content to a third-party server.$q$, $q$Journalists, NGOs, and privacy advocates$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$Data-sovereign office suite for institutions$q$, $q$Government agencies and public institutions self-host or contract CryptPad Enterprise to keep collaborative documents within jurisdictional or GDPR-compliant infrastructure.$q$, $q$Public sector and regulated organizations$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$Open-source project collaboration$q$, $q$Small teams and open-source communities use free CryptPad accounts for encrypted docs, kanban boards, and forms without vendor lock-in.$q$, $q$Open-source teams and small organizations$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$Free (CryptPad.fr)$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Baseline account storage","Full office suite access","Community support"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$Individual Premium (CryptPad.fr)$q$, $q$€5 to €100/month$q$, $q$monthly$q$, NULL, $q$["Additional storage","Priority support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$Enterprise Mini$q$, $q$€3,000/year (€1,500 for education/nonprofit)$q$, $q$annual$q$, NULL, $q$["50 users","100 GB storage","SSO integration","Managed or on-premise hosting"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$Enterprise Large$q$, $q$€25,000/year (€12,500 for education/nonprofit)$q$, $q$annual$q$, NULL, $q$["1,000 users","1 TB storage","SSO integration","Managed or on-premise hosting"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$CryptPad is an open-source, end-to-end encrypted office suite offering rich text documents, spreadsheets, presentations, kanban boards, a whiteboard, forms, and file storage. It grew out of a research project by Caleb James De Lisle at XWiki SAS, a Paris-based open-source software company, and is now maintained by a dedicated CryptPad team within XWiki led by David Benque.$q$, $q$The defining feature of CryptPad is its zero-knowledge architecture: all encryption and decryption happens in the user's browser, so the server operator, including the CryptPad.fr flagship instance, cannot read document content, file names, or credentials.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$CryptPad supports real-time collaborative editing through ChainPad, a CRDT-based algorithm designed specifically to synchronize encrypted documents without exposing plaintext to the server.$q$, $q$The suite covers the core needs of an office productivity tool, documents, spreadsheets, slides, code/markdown, kanban project boards, whiteboards, and forms, all under the same encrypted, self-hostable architecture.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$CryptPad is free and open source, and can be self-hosted at no cost. The flagship CryptPad.fr instance offers free accounts plus optional individual paid plans from about €5 to €100 per month for additional storage.$q$, $q$Organizations wanting a managed or dedicated deployment can purchase Enterprise plans starting around €1,500 per year, scaling from a 50-user/100GB Mini tier at about €3,000/year up to a 1,000-user/1TB Large tier at about €25,000/year, with a 50% discount for education and nonprofits.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', '4137e3dc-5b54-4d6a-adfa-85ce8104e38f') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('41beb071-a49d-4ab2-b0b3-1264edc2d746', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Unified semantic data model$q$, $q$Metrics, dimensions, and joins are defined once in code and reused consistently across every downstream tool.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Multi-protocol API access$q$, $q$The same semantic layer is queryable via a REST API, a GraphQL API, and a Postgres-compatible SQL API.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Open-source Cube Core$q$, $q$The core engine is Apache 2.0/MIT licensed and free to self-host, with roughly 20,000 GitHub stars.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Cube Store caching$q$, $q$A dedicated pre-aggregation and caching engine that accelerates query performance for large datasets.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Access control and governance$q$, $q$Row- and column-level security policies are defined centrally so every consuming tool respects the same permissions.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Agentic analytics support$q$, $q$AI copilots and LLM-based agents can query governed metrics directly, reducing the risk of hallucinated numbers.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$BI tool compatibility$q$, $q$Existing tools like Tableau, Power BI, and Looker Studio can connect to Cube as though it were a native database.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Embedded analytics$q$, $q$Software companies can embed dashboards and analytics chat directly inside their own customer-facing products.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Open-source core with a large, active GitHub community$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Headless architecture avoids vendor lock-in to a single BI front end$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Single governed metric definitions reduce inconsistent numbers across tools$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Increasingly positioned for AI/agentic use cases, not just traditional dashboards$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Usage-based Cube Compute Unit billing can make costs less predictable than flat per-seat pricing$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Requires engineering effort to define and maintain the semantic data model$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Premium tier requires a $10,000 annual consumption commitment$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Enterprise features like BYOC and custom LLM support require a custom quote$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$What is a semantic layer, and what does Cube do?$q$, $q$A semantic layer defines business metrics, dimensions, and access rules once so every tool that queries the data gets consistent results. Cube implements this as a headless platform accessible via SQL, REST, and GraphQL APIs.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Is Cube open source?$q$, $q$Yes. Cube Core, the underlying engine, is open source under Apache 2.0 (backend) and MIT (client) licenses and can be self-hosted for free. Cube Cloud is the company's paid, managed version.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$How is Cube priced?$q$, $q$Cube Cloud has a free tier, a Starter tier at $40/developer/month plus usage-based consumption, a Premium tier at $80/developer/month plus consumption with a $10K/year commitment, and custom Enterprise pricing.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Can Cube connect to my existing BI tool?$q$, $q$Yes. Cube exposes a Postgres-compatible SQL API, so tools like Tableau, Power BI, and Looker Studio can connect to it as if it were a regular database, in addition to REST and GraphQL APIs.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Is Cube designed for AI use cases?$q$, $q$Cube markets itself as an agentic analytics platform, letting AI copilots and LLM-based agents query governed metric definitions instead of raw tables, which reduces the risk of incorrect or hallucinated figures.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Who are Cube's main competitors?$q$, $q$Cube's closest competitors include dbt Labs' Semantic Layer (MetricFlow), Looker's LookML modeling layer, AtScale, and Kyligence.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Embedded analytics in SaaS products$q$, $q$Software companies use Cube to power in-app dashboards and reporting for their own customers without duplicating metric logic.$q$, $q$SaaS product and engineering teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Consistent enterprise metrics$q$, $q$Data platform teams centralize metric definitions in Cube so Tableau, Power BI, and internal tools all report the same numbers.$q$, $q$Data platform and analytics engineering teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$AI agent data access$q$, $q$Organizations connect AI copilots and chat assistants to Cube's semantic layer so they answer questions using governed, trustworthy metrics.$q$, $q$AI/ML and data teams building LLM-powered analytics$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Free$q$, $q$Free$q$, $q$forever$q$, NULL, $q$["Data source connections","Semantic layer IDE","Workbooks and dashboards"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Starter$q$, $q$$40/developer/month + ~$0.10/CCU ($99/month minimum)$q$, $q$monthly$q$, NULL, $q$["Extended agent limits","Premium LLM access","Unlimited workbooks","Production deployment","Cube Store caching"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Premium$q$, $q$$80/developer/month + ~$0.25/CCU ($10K/year commit)$q$, $q$annual commit$q$, NULL, $q$["Explorer/Viewer roles","Embedded dashboards and analytics chat","Unlimited queries","99.95% uptime SLA","Custom domains","Multi-cluster deployment"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["99.99% uptime SLA","Dedicated single-tenant deployment","Bring-your-own-cloud (BYOC)","Custom LLM support","SSO/SAML","DAX API for Power BI"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Cube is a headless, API-first semantic layer that lets data teams define metrics, dimensions, and access rules once and serve them consistently to BI tools, embedded analytics, and AI agents. Founded in 2016 by Artyom Keydunov and Pavel Tiunov and headquartered in San Francisco, the company evolved from the earlier Cube.js JavaScript framework into a dedicated semantic-layer platform.$q$, $q$Cube deliberately does not ship its own visualization front end. Instead it focuses on being the single source of governed metric definitions that Tableau, Power BI, internal apps, and AI copilots can all query consistently through SQL, REST, and GraphQL APIs.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Cube Core is open source (Apache 2.0 backend, MIT client libraries) with roughly 20,000 GitHub stars, and connects to most major SQL warehouses and databases while exposing a Postgres-compatible SQL API alongside REST and GraphQL endpoints.$q$, $q$Cube Cloud, the managed commercial product, adds Cube Store caching and pre-aggregations for performance, a semantic layer IDE, embedded dashboards, and agentic analytics support so AI copilots query governed metrics instead of raw, ungoverned tables.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Cube Cloud offers a free-forever tier for small projects, a Starter tier at $40 per developer per month plus usage-based Cube Compute Unit consumption ($99/month minimum), and a Premium tier at $80 per developer per month plus consumption with a $10,000 annual commitment.$q$, $q$Enterprise pricing is custom and adds a 99.99% SLA, single-tenant and bring-your-own-cloud deployment, custom LLM integration, SSO/SAML, and a DAX API for Power BI connectivity; the fully open-source Cube Core remains free to self-host indefinitely.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('7ae35df8-1db0-4f11-b030-bac3223a2cbe', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$Employee engagement surveys$q$, $q$Research-backed survey templates measure engagement, culture, and sentiment, with results benchmarked against industry peers.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$Performance management (Perform)$q$, $q$Goal-setting, continuous feedback, 360-degree reviews, and structured performance review cycles in one workflow.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$People analytics and benchmarking$q$, $q$Aggregated feedback data can be sliced by department and compared against industry, region, and company-size benchmarks.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$AI Coach$q$, $q$A generative AI feature that helps managers prepare for conversations, summarize open-ended comments, and draft development plans.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$Skills and career development (Develop)$q$, $q$An add-on module for mapping employee skills and building career development plans.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$People Science Consulting$q$, $q$Direct access to Culture Amp's in-house organizational psychologists for strategic advisory work.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$HRIS integrations$q$, $q$Connects with platforms like Workday, BambooHR, and ADP to sync employee data automatically.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$Enterprise security and compliance$q$, $q$SSO, data encryption, and SOC 2 compliance are included across all plans.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$Survey methodology grounded in organizational behavior and I/O psychology research$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$Strong benchmarking data across industries, regions, and company sizes$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$Combines engagement surveys and performance management in one platform$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$Support model scales with company size, including executive coaching for enterprise customers$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$Pricing is not publicly published and requires a sales quote$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$All contracts are billed annually, which may not suit companies wanting monthly flexibility$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$Additional modules like Develop and People Science Consulting cost extra$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$Can be a larger investment than lighter-weight pulse-survey-only tools for very small companies$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$How much does Culture Amp cost?$q$, $q$Culture Amp does not publish fixed pricing. Cost depends on employee headcount, which products (Engage, Perform, Develop) are purchased, and the service tier, with third-party estimates starting around $30 per employee per month; a formal quote requires contacting sales.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$What products does Culture Amp offer?$q$, $q$Culture Amp's core products are Engage for employee surveys and feedback, Perform for goal-setting and performance reviews, and Develop for skills and career development, plus an optional People Science Consulting add-on.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$Is Culture Amp only for large enterprises?$q$, $q$No. Culture Amp serves organizations of varying sizes, with tiered support models for companies under 200 employees, mid-market companies of 200 to 999 employees, and enterprises of 1,000 or more employees.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$Does Culture Amp use AI?$q$, $q$Yes. Culture Amp includes an AI Coach feature that helps managers prepare for conversations, summarizes open-ended survey comments, and drafts development plans.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$Who founded Culture Amp?$q$, $q$Culture Amp was founded in 2009 in Melbourne, Australia, by Didier Elzinga, Doug English, Rod Hamilton, and Jon Williams.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$Who are Culture Amp's main competitors?$q$, $q$Culture Amp's main competitors include Lattice, 15Five, Leapsome, Qualtrics EmployeeXM, and Microsoft Viva Glint.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$Company-wide engagement surveys$q$, $q$HR teams run annual and pulse engagement surveys to measure sentiment and benchmark results against industry peers.$q$, $q$HR and People Operations teams$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$Structured performance review cycles$q$, $q$People teams run goal-setting, continuous feedback, and 360-degree performance review cycles through the Perform product.$q$, $q$People managers and Talent teams$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$Manager coaching and development$q$, $q$Enterprise customers use AI Coach and People Science Consulting to help managers act on feedback and develop their teams.$q$, $q$Enterprise People and Learning & Development teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$Small/Medium (under 200 employees)$q$, $q$Custom quote$q$, $q$annual$q$, NULL, $q$["Group Customer Success support","24/5 chat and email support","Engage and/or Perform"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$Mid-Market (200-999 employees)$q$, $q$Custom quote$q$, $q$annual$q$, NULL, $q$["One-on-one Customer Success partnership","Expert-led implementation","24/5 chat and email support"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$Enterprise (1,000+ employees)$q$, $q$Custom quote$q$, $q$annual$q$, NULL, $q$["Manager and executive training","One-on-one and group coaching","Dedicated support"]$q$::jsonb, 2);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Culture Amp is an employee experience platform combining engagement surveys, performance management, and people analytics, grounded in research-based people science. Founded in 2009 in Melbourne, Australia, by Didier Elzinga, Doug English, Rod Hamilton, and Jon Williams, the company has grown into a global unicorn serving more than 6,500 companies and 25 million-plus employees.$q$, $q$Culture Amp reached a $1.5 billion valuation after a $150 million Series F round in July 2021 led by Sequoia Capital China and TDM Growth Partners, bringing its total funding to roughly $258 million from investors including Sequoia Capital, Index Ventures, and Blackbird Ventures.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$The platform is organized around Engage for surveys and continuous feedback, Perform for goal-setting and performance review cycles, and Develop for skills and career growth planning, all underpinned by scientifically validated survey methodology and industry benchmarking data.$q$, $q$Generative AI features, delivered through AI Coach, help managers prepare for conversations, summarize open-ended feedback, and draft development plans, while People Science Consulting gives customers direct access to Culture Amp's in-house organizational psychologists.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Culture Amp does not publish fixed pricing. Costs depend on employee headcount, which products are purchased, and the service tier, and all contracts are billed annually rather than monthly.$q$, $q$Support and service levels scale with company size, from group-based Customer Success for organizations under 200 employees to dedicated one-on-one partnerships and executive coaching for enterprise customers with 1,000 or more employees; third-party estimates place entry pricing near $30 per employee per month for smaller deployments.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('8260c82f-10fa-4ece-b662-6c99bd5967eb', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$Internet Printing Protocol (IPP) support$q$, $q$CUPS communicates with modern network printers using IPP, offering better capability discovery than legacy LPD-based printing.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$Cross-platform default$q$, $q$CUPS ships by default with most Linux distributions and macOS, making it the de facto standard printing system for Unix-like operating systems.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$Web-based administration$q$, $q$A built-in web interface, typically on port 631, lets administrators configure printers, manage queues, and set access permissions.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$Filter-based document conversion$q$, $q$A pipeline of filters converts documents from application formats into formats specific printers can understand.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$Backward-compatible command-line tools$q$, $q$Standard Unix printing commands like lp and lpr continue to work on top of CUPS's IPP-based internals.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$Modular backends$q$, $q$Print jobs can be routed to printers over USB, network IPP, and other connection types through pluggable backend modules.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$Open-source licensing$q$, $q$CUPS is released under Apache License 2.0 with a GPLv2 linking exception, allowing free use, modification, and redistribution.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$Active OpenPrinting development$q$, $q$The OpenPrinting organization maintains ongoing development, including the CUPS 3.x generation and companion libraries like libcups and PAPPL.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$Completely free and open source with no licensing cost$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$Bundled by default with virtually every major Linux distribution and macOS$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$Standards-based IPP architecture offers broad printer compatibility$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$Actively maintained by OpenPrinting with an ongoing CUPS 3.x development track$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$Configuration and troubleshooting can require Unix system administration knowledge$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$No commercial support organization behind it the way a SaaS vendor would offer$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$Print driver quality still varies by printer manufacturer despite IPP standardization$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$Documentation and tooling are oriented toward technical users rather than general consumers$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$What does CUPS stand for?$q$, $q$CUPS originally stood for the Common UNIX Printing System, though the name was shortened to just CUPS starting with version 1.4 due to trademark concerns over the term UNIX.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$Who created CUPS?$q$, $q$CUPS was created by Michael Sweet, who began development in 1997 through his company Easy Software Products, with the first public betas released in 1999.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$Does Apple own CUPS?$q$, $q$Apple acquired the CUPS source code and hired its chief developer, Michael Sweet, in February 2007, and used CUPS as macOS's printing system. Since Sweet left Apple in 2019, upstream development has been led by the OpenPrinting organization, though CUPS remains open source.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$Is CUPS free to use?$q$, $q$Yes. CUPS is free and open-source software licensed under Apache License 2.0 with a GPLv2 linking exception, and it comes bundled by default with most Linux distributions and macOS.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$What protocol does CUPS use to communicate with printers?$q$, $q$CUPS uses the Internet Printing Protocol (IPP), an HTTP-based standard, rather than the older Line Printer Daemon (LPD) protocol used by earlier Unix printing systems.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$Who maintains CUPS today?$q$, $q$Since 2020, upstream development of CUPS has been maintained by OpenPrinting, a community and industry organization focused on Linux and Unix printing standards.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$Default Linux/macOS printing$q$, $q$CUPS runs invisibly in the background on Linux and macOS systems to handle everyday document and network printing.$q$, $q$General desktop and laptop users$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$Shared network printing$q$, $q$System administrators use CUPS's web interface and IPP support to configure shared printers accessible across a home or office network.$q$, $q$System administrators$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$Custom printer applications$q$, $q$Developers use CUPS-related libraries like libcups and PAPPL to build modern IPP-based printer applications and drivers.$q$, $q$Software and driver developers$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$Open Source$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Full source code access","Free use, modification, and redistribution under Apache License 2.0"]$q$::jsonb, 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$CUPS (Common Unix Printing System) is a free, open-source printing system that provides the standard printing architecture for Linux, macOS, and other Unix-like operating systems. Development began in 1997, led by Michael Sweet of Easy Software Products, with public betas arriving in 1999, and the project moved to using the Internet Printing Protocol (IPP) instead of the older Line Printer Daemon protocol.$q$, $q$Apple adopted CUPS as the printing system for Mac OS X 10.2 in March 2002 and later hired Michael Sweet and acquired the CUPS source code in February 2007. Since Sweet's departure from Apple in December 2019, upstream development has been stewarded by OpenPrinting.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$CUPS uses the Internet Printing Protocol as its core transport, giving it richer printer discovery and better vendor compatibility than older LPD-based printing systems, while still supporting legacy lp and lpr commands for backward compatibility.$q$, $q$The system is modular, combining a scheduler daemon, document-conversion filters, device backends, and a web-based administrative interface, and is complemented by newer OpenPrinting components like libcups and PAPPL for building modern IPP printer applications.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$CUPS is free and open source, licensed under Apache License 2.0 with a GPLv2 linking exception, and is bundled by default with virtually every major Linux distribution and macOS at no cost.$q$, $q$Because it is infrastructure software rather than a commercial SaaS product, there is no paid tier, subscription, or enterprise pricing plan; ongoing development is sustained by the OpenPrinting community rather than a commercial licensing model.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', '326f20ae-646d-484a-96b8-335f75262ea9') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', 'efe7ced3-7cfa-4b39-9792-3427d24fa58d') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', '97eb8f3e-e378-4a5d-b2a5-331706e86e50') ON CONFLICT DO NOTHING;
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('0fe96227-1d6d-4bd6-83ce-4ceea48aafd2', '96595ec7-e449-4fd5-803d-e73ba922c0ca') ON CONFLICT DO NOTHING;
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Agentic multi-file editing$q$, $q$The AI agent can plan and execute coding tasks across many files in a codebase from a single natural-language instruction.$q$, 0);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Tab autocomplete$q$, $q$Predictive, multi-line code completion that suggests entire edits rather than single lines or tokens.$q$, 1);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Bugbot code review$q$, $q$Automated review that flags likely bugs and issues directly in pull requests.$q$, 2);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Cloud Agents$q$, $q$Coding agents can run asynchronously in the background rather than requiring an active local editor session.$q$, 3);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Model Context Protocol (MCP) support$q$, $q$Connects external tools, data sources, and custom skills to Cursor's AI agents.$q$, 4);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Multi-model access$q$, $q$Users can choose among frontier models from Anthropic, OpenAI, and Google, plus Anysphere's own Composer model.$q$, 5);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$VS Code compatibility$q$, $q$Built as a fork of Visual Studio Code, preserving compatibility with existing extensions, themes, and keyboard shortcuts.$q$, 6);
INSERT INTO tool_features (tool_id, title, description, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Enterprise governance controls$q$, $q$SCIM provisioning, audit logs, repository and model access controls, and an AI code-tracking API for large organizations.$q$, 7);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Deeply integrated, codebase-aware AI agent rather than a bolt-on chat sidebar$q$, 0);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Access to multiple frontier models instead of being locked to one provider$q$, 1);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Familiar VS Code-based interface with compatible extensions and shortcuts$q$, 2);
INSERT INTO tool_pros (tool_id, text, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Free Hobby tier makes it easy to try before committing to a paid plan$q$, 3);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Usage-based billing changes have previously caused unexpected charges for some users$q$, 0);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Heavy agentic use can consume model usage quickly, requiring plan upgrades$q$, 1);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Enterprise-grade governance features require a custom-priced Enterprise plan$q$, 2);
INSERT INTO tool_cons (tool_id, text, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Ongoing acquisition by SpaceX introduces some uncertainty about the product's long-term roadmap and ownership$q$, 3);
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$What company makes Cursor?$q$, $q$Cursor is made by Anysphere, Inc., a San Francisco-based company founded in 2022 by Michael Truell, Sualeh Asif, Aman Sanger, and Arvid Lunnemark.$q$, 0, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Is Cursor free to use?$q$, $q$Yes. Cursor offers a free Hobby plan with limited Agent requests and Tab completions and no credit card required. Paid plans start at $16/month for Individual and $32/user/month for Teams.$q$, 1, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Is Cursor based on VS Code?$q$, $q$Yes. Cursor is built as a fork of Microsoft's open-source Visual Studio Code, which preserves compatibility with most VS Code extensions and keyboard shortcuts while adding deeply integrated AI features.$q$, 2, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$What is Cursor's Agent feature?$q$, $q$Agent, also referred to as Composer, is Cursor's autonomous coding mode that can plan and execute multi-step, multi-file coding tasks from natural-language instructions with limited supervision.$q$, 3, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Which AI models does Cursor support?$q$, $q$Cursor gives users access to multiple frontier models from providers including Anthropic, OpenAI, and Google, as well as Anysphere's own in-house Composer model.$q$, 4, 'published');
INSERT INTO tool_faqs (tool_id, question, answer, sort_order, status) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Is Cursor being acquired?$q$, $q$In June 2026, SpaceX announced an agreement to acquire Anysphere, Cursor's parent company, in an all-stock deal valuing it at roughly $60 billion, with the transaction expected to close in the third quarter of 2026.$q$, 5, 'published');
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Individual developer productivity$q$, $q$Solo developers use Cursor's Tab autocomplete and Agent mode to write and refactor code faster inside a familiar VS Code-based editor.$q$, $q$Individual software engineers$q$, 0);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Team code review automation$q$, $q$Engineering teams use Bugbot to automatically flag likely bugs in pull requests before human review.$q$, $q$Engineering teams and tech leads$q$, 1);
INSERT INTO tool_use_cases (tool_id, title, description, audience, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Enterprise-governed AI coding$q$, $q$Large organizations deploy Cursor Enterprise with SCIM, audit logs, and access controls to safely roll out AI coding assistance across many engineers.$q$, $q$Enterprise engineering and platform teams$q$, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Hobby$q$, $q$Free$q$, $q$N/A$q$, NULL, $q$["Limited Agent requests","Limited Tab completions","No credit card required"]$q$::jsonb, 0);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Individual$q$, $q$$16/month$q$, $q$monthly$q$, NULL, $q$["Extended Agent limits","Access to frontier models","MCP, skills, and hooks","Cloud agents","Usage-based Bugbot"]$q$::jsonb, 1);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Teams$q$, $q$$32/user/month$q$, $q$monthly$q$, NULL, $q$["Centralized team billing and administration","Team marketplace","Agentic code review (Bugbot)","Shared-context cloud agents","Usage analytics","SAML/OIDC SSO"]$q$::jsonb, 2);
INSERT INTO tool_pricing_plans (tool_id, plan_name, price, billing_cycle, description, features, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$Enterprise$q$, $q$Custom$q$, $q$annual$q$, NULL, $q$["Pooled usage","Invoice/PO billing","SCIM seat management","Repository, model, and MCP access controls","Audit logs and service accounts","AI code tracking API"]$q$::jsonb, 3);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$overview$q$, $q$Overview$q$, 2, ARRAY[$q$Cursor is an AI-native code editor, forked from Visual Studio Code, built by Anysphere, Inc., a San Francisco company founded in 2022 by MIT students and dropouts Michael Truell, Sualeh Asif, Aman Sanger, and Arvid Lunnemark. Rather than bolting AI chat onto a traditional editor, Cursor is designed around agentic workflows where the AI can read across a codebase, edit multiple files, run terminal commands, and iterate based on test or error output.$q$, $q$Anysphere has grown at an unusually fast pace, moving from an $8 million seed round in October 2023 to a $29.3 billion valuation by November 2025, and in June 2026 SpaceX announced an agreement to acquire Anysphere in an all-stock deal valuing the company at roughly $60 billion, with the deal expected to close in Q3 2026.$q$]::text[], 0);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$key-features$q$, $q$Key Features$q$, 2, ARRAY[$q$Core features include Tab, a predictive multi-line autocomplete; Agent (Composer), an autonomous multi-file coding mode; Bugbot, automated pull-request code review; and Cloud Agents, which let coding agents run asynchronously in the background rather than only in a live editor session.$q$, $q$Cursor supports the Model Context Protocol (MCP) for connecting external tools, and gives users access to multiple frontier AI models from Anthropic, OpenAI, and Google alongside Anysphere's own Composer model, rather than locking developers into a single provider.$q$]::text[], 1);
INSERT INTO tool_content_blocks (tool_id, block_key, heading, level, paragraphs, sort_order) VALUES ('693230a0-d462-46dc-9108-9752df61caba', $q$pricing-overview$q$, $q$Pricing$q$, 2, ARRAY[$q$Cursor offers a free Hobby tier with limited Agent and Tab usage, an Individual plan at $16 per month with extended limits and frontier model access, and a Teams plan at $32 per user per month adding centralized billing, Bugbot code review, and SSO.$q$, $q$Enterprise pricing is custom and adds pooled usage, SCIM provisioning, granular access controls, audit logs, and an AI code-tracking API; a July 2025 change to usage-based billing on the paid individual tier drew user complaints, which Cursor addressed with limit adjustments and refunds.$q$]::text[], 2);
INSERT INTO tool_tag_links (tool_id, tag_id) VALUES ('693230a0-d462-46dc-9108-9752df61caba', 'c296bd6a-c865-41d7-8807-5dce653dd3f5') ON CONFLICT DO NOTHING;
